+/// Check if a method name is a unittest assertion method
+fn isUnittestMethod(method_name: []const u8) bool {
+    const unittest_methods = [_][]const u8{
+        "assertEqual",
+        "assertTrue",
+        "assertFalse",
+        "assertIsNone",
+        "assertGreater",
+        "assertLess",
+        "assertGreaterEqual",
+        "assertLessEqual",
+        "assertNotEqual",
+        "assertIs",
+        "assertIsNot",
+        "assertIsNotNone",
+        "assertIn",
+        "assertNotIn",
+        "assertAlmostEqual",
+        "assertNotAlmostEqual",
+        "assertCountEqual",
+        "assertRaises",
+        "assertRaisesRegex",
+        "assertRegex",
+        "assertNotRegex",
+        "assertIsInstance",
+        "assertNotIsInstance",
+        "assertIsSubclass",
+        "assertNotIsSubclass",
+        "assertWarns",
+        "assertWarnsRegex",
+        "assertStartsWith",
+        "assertNotStartsWith",
+        "assertEndsWith",
+        "assertHasAttr",
+        "assertNotHasAttr",
+        "assertSequenceEqual",
+        "assertListEqual",
+        "assertTupleEqual",
+        "assertSetEqual",
+        "assertDictEqual",
+        "assertMultiLineEqual",
+        "assertLogs",
+        "assertNoLogs",
+        "fail",
+        "skipTest",
+        "assertFloatsAreIdentical",
+    };
+    for (unittest_methods) |m| {
+        if (std.mem.eql(u8, method_name, m)) return true;
+    }
